const events = [
  { id: 'e001', type: 'funding', company: 'CompetitorX', amount_usd: 80000000, round: 'Series C', investors: ['Sequoia','Andreessen Horowitz'], date: '2026-07-10', source: 'TechCrunch', url: 'https://example.com/competitorx-series-c', notes: 'Plans to expand sales team and launch enterprise tier.' },
  { id: 'e002', type: 'acquisition', company: 'CompetitorY', acquired: 'DataMesh Inc', price_usd: 12000000, date: '2026-07-08', source: 'Crunchbase', url: 'https://example.com/competitory-datamesh', notes: 'DataMesh builds data pipeline tooling. Likely to add native connectors to CompetitorY product.' },
  { id: 'e003', type: 'key_hire', company: 'CompetitorX', hire_name: 'Sarah Chen', hire_role: 'VP Enterprise Sales (from Salesforce)', date: '2026-07-07', source: 'LinkedIn', url: 'https://example.com/competitorx-vp-hire', notes: 'Chen scaled Salesforce enterprise motion from $10M to $150M ARR. Signal: CompetitorX targeting enterprise seriously.' },
  { id: 'e004', type: 'funding', company: 'NewEntrant Co', amount_usd: 5000000, round: 'Seed', investors: ['YCombinator'], date: '2026-07-06', source: 'YC', url: 'https://example.com/newentrant-seed', notes: 'Building AI-native project management. YC S26. 200 waitlist signups.' }
];
return [{ json: { events, total: events.length, period: 'week of 2026-07-07 to 2026-07-14' } }];

const { events, total, period } = $input.first().json;
if (!events || events.length === 0) {
  throw new Error('No funding/MA events found');
}
const competitors = $env.FUNDING_COMPETITORS || 'CompetitorX,CompetitorY';
const eventText = events.map((e, i) =>
  `[${i+1}] Type: ${e.type} | Company: ${e.company}\nDate: ${e.date} | Source: ${e.source}\nDetails: ${e.type === 'funding' ? `$${(e.amount_usd/1e6).toFixed(0)}M ${e.round} from ${(e.investors||[]).join(', ')}` : e.type === 'acquisition' ? `Acquired ${e.acquired} for $${((e.price_usd||0)/1e6).toFixed(0)}M` : `${e.hire_name || 'unnamed'} as ${e.hire_role}`}\nNotes: ${e.notes}`
).join('\n\n');
const system = `You are a competitive intelligence analyst. You interpret market events and explain their implications for positioning, pricing, and product strategy. Be specific, not generic. Return ONLY valid JSON.`;
const user = `Analyse these ${events.length} market events from ${period} and explain their implications for positioning.

Our tracked competitors: ${competitors}

Events:
${eventText}

Return JSON:
{
  "event_assessments": [
    {
      "id": "string",
      "company": "string",
      "event_type": "string",
      "significance": "high|medium|low",
      "positioning_implications": "string",
      "estimated_timeline_impact": "string — when this might affect deals",
      "recommended_response": "string"
    }
  ],
  "aggregate_signal": "string — what these events collectively signal about market direction",
  "our_biggest_risk": "string",
  "our_biggest_opportunity": "string",
  "confidence": "low|medium|high"
}`;
return [{ json: { events, total, period, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Analysis Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No content');
  parsed = JSON.parse(content);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.event_assessments || !Array.isArray(parsed.event_assessments)) {
  return [{ json: { _error: true, reason: 'Missing event_assessments array' } }];
}
return [{ json: { _error: false, analysis: parsed, meta: { period: upstream.period, total: upstream.total, generated_at: new Date().toISOString() } } }];

const { analysis: a, meta: m } = $input.first().json;
const assessLines = (a.event_assessments || []).map(e =>
  `  [${e.significance.toUpperCase()}] ${e.company} — ${e.event_type}\n  Implications: ${e.positioning_implications}\n  Timeline: ${e.estimated_timeline_impact}\n  Response: ${e.recommended_response}`
).join('\n\n');
const report = [
  `FUNDING & M&A TRACKER — ${m.period}`,
  `Events reviewed: ${m.total} | Generated: ${m.generated_at} | Confidence: ${a.confidence}`,
  ``,
  `AGGREGATE SIGNAL: ${a.aggregate_signal}`,
  ``,
  `OUR BIGGEST RISK: ${a.our_biggest_risk}`,
  `OUR BIGGEST OPPORTUNITY: ${a.our_biggest_opportunity}`,
  ``,
  `EVENT ASSESSMENTS:`,
  assessLines || '  (none)',
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
